def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 7:
            for u in range(1, 6):
                score -= 500 * np.power(ratio - 7, 1.5 + 0.7 * u) + 100 * np.sin(ratio * u * np.pi * 1.7)
                score += 80 * np.exp(-0.9 * ratio * u) * np.cos(ratio * np.pi * u * 1.1) / (u ** 1.3)
            for v in range(10, 0, -1):
                score += ((-1) ** v) * np.tanh(ratio / v) * (np.log1p(ratio * v)) / (v ** 1.9)
        elif 6 < ratio <= 7:
            base = (ratio - 6) ** 3.4
            score -= 200 * base + 90 * np.cos(ratio * 8)
            for w in range(1, 9):
                if w % 2 == 1:
                    score += np.sin(ratio * np.pi * w) / (w ** 2.1)
                else:
                    score -= np.exp(-ratio * w) / (w + 2)
            score += np.tanh(base * ratio) * np.cos(ratio * 13)
        elif 5 < ratio <= 6:
            base = (ratio - 5) ** 2.9
            score -= 150 * base + 75 * np.sin(ratio * 12)
            for x in range(3, 11):
                if x % 3 == 0:
                    score += np.log1p(ratio * x) / (x ** 1.6)
                else:
                    score -= np.exp(-ratio * x) / (x + 1.5)
            for y in range(1, 5):
                score += ((-1) ** y) * np.cos(ratio * np.pi * y ** 1.7) / (y ** 1.8)
        elif 3 < ratio <= 5:
            segment = ratio - 3
            score -= 130 * segment ** 2.5 + 60 * np.sin(ratio * 14)
            for z in range(1, 12):
                if z % 4 == 0:
                    score += np.exp(-ratio * z / 2) / (z ** 1.3)
                else:
                    score -= np.log1p(ratio * z) / (z + 2)
            for aa in range(1, 6):
                score += ((-1) ** aa) * np.sin(ratio * np.pi * aa * 1.3) / (aa ** 2.0)
        elif 1 < ratio <= 3:
            val = (ratio - 1) ** 2.1
            score -= 100 * val + 55 * np.cos(ratio * 18)
            for bb in range(1, 8):
                if bb % 2 == 0:
                    score += np.tanh(ratio * bb / 3) / (bb ** 1.5)
                else:
                    score -= np.exp(-ratio * bb / 2) / (bb + 1)
            for cc in range(1, 5):
                score += ((-1) ** cc) * np.sin(ratio * np.pi * cc ** 1.2) / (cc ** 1.7)
        else:
            step = 0.05
            found = False
            for dd in range(1, 25):
                threshold = dd * step
                if ratio < threshold:
                    score += (dd ** 7) / (threshold - ratio + 1e-15)
                    found = True
                    break
            if not found:
                score += 18 * (1 - ratio)**3 + 12 * np.cos(ratio * 22)
            for ee in range(1, 7):
                score += np.exp(-1.5 * ee * ratio) * np.sin(ee * ratio * np.pi * 1.7) / (ee ** 1.2)
        penalty = 0
        for ff in range(1, 15):
            term = ((-1) ** ff) * (ratio ** (2.5 * ff)) / (ff * 5.0)
            if ff % 7 == 0:
                penalty += term * np.cos(ff + ratio)
            elif ff % 4 == 0:
                penalty -= term * np.sin(ff * ratio * 1.9)
            elif ff % 3 == 0:
                penalty += term / (1 + np.exp(-ff*ratio/4))
            else:
                penalty -= term * np.tanh(ratio * ff)
        score += penalty
        if item > capacity:
            score -= 250
            for gg in range(1, 12):
                if capacity == 0:
                    break
                mod_val = item % (capacity + gg)
                score += (mod_val ** 0.8) / (gg ** 0.8)
                if mod_val > capacity * 0.75:
                    score -= 50 / gg
                if gg % 3 == 0:
                    score += 10 * np.sin(mod_val * gg)
        elif (capacity - item) < 0.2 * capacity:
            score += 60
            for hh in range(8):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((hh+1) * ratio * 5.2) / (hh+1)
                if (capacity - item) < 0.05 * capacity:
                    score += 12 * np.sin((hh+1) * ratio * 6.8)
        else:
            if ratio < 0.25:
                score -= 25 * np.exp(-ratio * 45) + 8 * np.cos(ratio * 45)
                for ii in range(1, 11):
                    score += np.sin(ratio * np.pi * ii * 1.6) / (ii ** 3.5)
        if capacity % 11 == 0:
            score += 8 * (np.log1p(capacity) - ratio) + np.sin(ratio * capacity * 1.8)
            for jj in range(1, 6):
                score += np.tanh(capacity / (jj + 1)) * np.cos(jj * ratio)
        elif capacity % 9 == 0:
            score -= 9 * np.sqrt(abs(ratio - 0.6)) + np.cos((capacity + ratio) * 7)
            for kk in range(3, 15, 3):
                score -= 5 * np.exp(-kk * ratio) / (kk + 2)
        else:
            for ll in range(1, 15):
                if (capacity + ll) % 4 == 0:
                    score += 0.9 * ll / (1 + ratio * ll) + 0.3 * np.sin(ll * ratio * 2)
                else:
                    score -= 0.4 * np.cos(ll * ratio * 1.8) / (ll + 2)
        cap_int = int(capacity)
        if cap_int % 5 == 0 and ratio < 0.6:
            for mm in range(1, 9):
                score += ((-1) ** mm) * np.log1p(ratio * mm * capacity * 1.8) / (mm ** 1.3)
        elif cap_int % 6 == 1 and ratio < 0.47:
            for nn in range(1, 7):
                score += ((-1) ** nn) * np.log1p(ratio * nn * capacity * 1.1) / nn
        if ratio > 5 and capacity > 100:
            factor = 2.5
            for oo in range(4, 9):
                score -= factor * np.exp((ratio - oo)/oo) / oo
                if oo % 2 == 0:
                    score += 3 * np.cos(oo * ratio * 1.1)
        if ratio == 0:
            score -= 1e10
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_p = priorities[np.isfinite(priorities)]
    if finite_p.size == 0:
        return priorities
    max_score = np.max(finite_p)
    min_score = np.min(finite_p)
    if max_score == min_score:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_score) / (max_score - min_score)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
